import json

class JSONMixin:
    """Adds JSON serialization/deserialization."""
    def to_json(self) -> str:
        return json.dumps(self.__dict__, default=str)

    @classmethod
    def from_json(cls, json_str: str):
        data = json.loads(json_str)
        return cls(**data)

class ReprMixin:
    """Adds automatic __repr__ based on __dict__."""
    def __repr__(self) -> str:
        attrs = ", ".join(f"{k}={v!r}" for k, v in self.__dict__.items())
        return f"{self.__class__.__name__}({attrs})"

class ComparableMixin:
    """Adds comparison based on a 'sort_key' property."""
    def __lt__(self, other):
        if not isinstance(other, self.__class__):
            return NotImplemented
        return self.sort_key < other.sort_key

    def __eq__(self, other):
        if not isinstance(other, self.__class__):
            return NotImplemented
        return self.sort_key == other.sort_key

# Compose mixins into a concrete class
class User(JSONMixin, ReprMixin, ComparableMixin):
    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    @property
    def sort_key(self):
        return self.age

