from typing import Protocol
from abc import ABC, abstractmethod

# BAD: Fat interface forces unused implementations
class BadWorker(ABC):
    @abstractmethod
    def work(self): ...
    @abstractmethod
    def eat(self): ...
    @abstractmethod
    def code(self): ...
    @abstractmethod
    def manage(self): ...

# Managers forced to implement code(), developers forced to implement manage()

# GOOD: Segregated protocols
class Workable(Protocol):
    def work(self) -> str: ...

class Feedable(Protocol):
