class Closable(ABC):
    @abstractmethod
    def close(self) -> None:
        ...

    @classmethod
    def __subclasshook__(cls, C):
        if cls is Closable:
            # Check if C has a 'close' method
            if any("close" in B.__dict__ for B in C.__mro__):
                return True
        return NotImplemented

