print(isinstance(FileWrapper(), Closable))  # True
print(isinstance(Connection(), Closable))   # True
print(isinstance(NoClose(), Closable))      # False

print(issubclass(FileWrapper, Closable))    # True
print(issubclass(NoClose, Closable))        # False

